```bash
cat > ~/.config/nanoclaw/sender-allowlist.json << 'EOF'
{
  "default": { "allow": "*", "mode": "trigger" },
  "chats": {
    "972542328676-1499156528@g.us": {
      "allow": ["972542328676@s.whatsapp.net"],
      "mode": "trigger"
    },
    "972545259144@s.whatsapp.net": {
      "allow": ["972542328676@s.whatsapp.net"],
      "mode": "trigger"
    }
  },
  "logDenied": true
}
EOF
```

